import React, { useRef } from 'react';
import { motion, useInView } from 'framer-motion';
import { HiCalendar, HiLocationMarker, HiOfficeBuilding } from 'react-icons/hi';
import { experience } from '../data/portfolioData';

function TimelineItem({ item, index, total }) {
  const ref = useRef(null);
  const isInView = useInView(ref, { once: true, margin: '-60px' });

  return (
    <motion.div
      ref={ref}
      initial={{ opacity: 0, x: -25 }}
      animate={isInView ? { opacity: 1, x: 0 } : {}}
      transition={{ duration: 0.65, delay: index * 0.18 }}
      className="relative pl-10 pb-10 last:pb-0"
    >
      {/* Vertical line */}
      {index < total - 1 && (
        <div className="absolute left-[11px] top-7 bottom-0 w-px bg-gradient-to-b from-[#6c63ff]/40 to-transparent" />
      )}

      {/* Timeline node */}
      <div className="absolute left-0 top-1.5 w-6 h-6 flex items-center justify-center rounded-full border-2 border-[#6c63ff] bg-[#0a0a0f]">
        <div className="w-2 h-2 rounded-full bg-[#6c63ff]" />
      </div>

      <div className="p-6 rounded-2xl border border-white/[0.06] bg-gradient-to-br from-[#0f0f1a] to-[#0a0a10] hover:border-[#6c63ff]/20 transition-all duration-300">
        <div className="flex flex-wrap items-start justify-between gap-2 mb-3">
          <h3 className="font-space font-bold text-white text-lg">{item.title}</h3>
          <span className="flex items-center gap-1.5 text-xs font-mono text-slate-500 bg-white/[0.03] border border-white/[0.06] px-3 py-1 rounded-full">
            <HiCalendar size={11} /> {item.period}
          </span>
        </div>
        <div className="flex flex-wrap gap-4 mb-4">
          <span className="flex items-center gap-1.5 text-sm text-[#6c63ff] font-medium">
            <HiOfficeBuilding size={14} /> {item.company}
          </span>
          <span className="flex items-center gap-1.5 text-sm text-slate-500">
            <HiLocationMarker size={14} /> {item.location}
          </span>
        </div>
        <p className="text-slate-400 text-sm leading-relaxed">{item.description}</p>
      </div>
    </motion.div>
  );
}

export default function Experience() {
  const ref = useRef(null);
  const isInView = useInView(ref, { once: true, margin: '-100px' });

  return (
    <section id="experience" className="py-28 px-6">
      <div className="max-w-3xl mx-auto">
        <motion.div
          ref={ref}
          initial={{ opacity: 0, y: 20 }}
          animate={isInView ? { opacity: 1, y: 0 } : {}}
          transition={{ duration: 0.6 }}
          className="text-center mb-16"
        >
          <span className="font-mono text-[#6c63ff] text-sm tracking-widest uppercase">// career</span>
          <h2 className="font-space text-4xl md:text-5xl font-bold text-white mt-3 mb-4">
            Experience
          </h2>
        </motion.div>

        {experience.map((item, i) => (
          <TimelineItem key={i} item={item} index={i} total={experience.length} />
        ))}
      </div>
    </section>
  );
}
